"use strict";(self.webpackChunkzhishi=self.webpackChunkzhishi||[]).push([[1818],{392:(n,s,a)=>{a.r(s),a.d(s,{data:()=>p});const p={key:"v-2696244f",path:"/fe/js/4-1-this%E5%92%8C%E6%89%A7%E8%A1%8C%E4%B8%8A%E4%B8%8B%E6%96%87.html",title:"this的指向",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"this 是什么",slug:"this-是什么",children:[]},{level:2,title:"全局上下文",slug:"全局上下文",children:[]},{level:2,title:"1、纯粹的函数调用",slug:"_1、纯粹的函数调用",children:[]},{level:2,title:"2、作为 对象 的一个方法",slug:"_2、作为-对象-的一个方法",children:[]},{level:2,title:"3、作为 构造函数 调用",slug:"_3、作为-构造函数-调用",children:[]},{level:2,title:"apply / call 调用",slug:"apply-call-调用",children:[]},{level:2,title:"箭头函数",slug:"箭头函数",children:[]},{level:2,title:"参考",slug:"参考",children:[]}],filePathRelative:"fe/js/4-1-this和执行上下文.md",git:{updatedTime:162659897e4,contributors:[{name:"tangxue",email:"11183504@qq.com",commits:1}]}}},376:(n,s,a)=>{a.r(s),a.d(s,{default:()=>c});var p=a(6252);const e=(0,p.uE)('<h1 id="this的指向" tabindex="-1"><a class="header-anchor" href="#this的指向" aria-hidden="true">#</a> this的指向</h1><h3 id="this-是什么" tabindex="-1"><a class="header-anchor" href="#this-是什么" aria-hidden="true">#</a> this 是什么</h3><p>MDN 上这样写的：</p><blockquote><p>In most cases, the value of this is determined by how a function is called.</p><p>在绝大多数情况下，函数的调用方式决定了this的值。</p></blockquote><p>在 js 中 <code>this</code> 的指向是调用时决定的，而不是创建的时候决定的。</p><p><strong><code>this</code> 总会指向，调用函数的那个对象</strong></p><p><strong>this 其实不难，看清楚有木有箭头函数或者是 call apply bind ，其他就是看调用对象</strong></p><h2 id="全局上下文" tabindex="-1"><a class="header-anchor" href="#全局上下文" aria-hidden="true">#</a> 全局上下文</h2><p>在全局上下文中，<code>this</code> 都指向全局对象</p><p>浏览器里面 <code>this</code> 等价于 <code>window</code> 对象，声明的一些全局变量，都会挂在 <code>window</code> 上</p><ul><li><p><code>this</code> 等价于 <code>window</code> 对象</p></li><li><p><code>var</code> === <code>this</code> === <code>window</code></p></li></ul><h2 id="_1、纯粹的函数调用" tabindex="-1"><a class="header-anchor" href="#_1、纯粹的函数调用" aria-hidden="true">#</a> 1、纯粹的函数调用</h2><p>函数属于全局性的调用，<code>this</code> 指向全局对象 <code>window</code></p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">this</span><span class="token punctuation">.</span>x <span class="token operator">=</span> <span class="token number">1</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>x<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n<span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// 1</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="_2、作为-对象-的一个方法" tabindex="-1"><a class="header-anchor" href="#_2、作为-对象-的一个方法" aria-hidden="true">#</a> 2、作为 对象 的一个方法</h2><p><code>this</code> 指向<strong>这个上级对象</strong></p><ul><li><code>person</code> 调用了 <code>getName</code>，<code>this</code> 是对象本身</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">var</span> person <span class="token operator">=</span> <span class="token punctuation">{</span>\n  name<span class="token operator">:</span> <span class="token string">&#39;123&#39;</span><span class="token punctuation">,</span>\n  <span class="token function-variable function">getName</span><span class="token operator">:</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>name\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>person<span class="token punctuation">.</span><span class="token function">getName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 123 （person 调用了 getName，this 是对象本身）</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><ul><li><code>person.getName</code> 赋值了一个全局变量 <code>getName</code>，<code>getName</code> 在全局调用，<code>this</code> 指向 <code>window</code></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">var</span> name <span class="token operator">=</span> <span class="token string">&#39;hj&#39;</span>\n<span class="token keyword">var</span> person <span class="token operator">=</span> <span class="token punctuation">{</span>\n  name<span class="token operator">:</span> <span class="token string">&#39;123&#39;</span><span class="token punctuation">,</span>\n  <span class="token function-variable function">getName</span><span class="token operator">:</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>name\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">var</span> getName <span class="token operator">=</span> person<span class="token punctuation">.</span><span class="token function">getName</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token function">getName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// hj (person.getName 赋值了一个全局变量 getName ，getName 在全局调用)</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><ul><li><code>getName</code> 是箭头函数，箭头函数指向外层</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">var</span> person <span class="token operator">=</span> <span class="token punctuation">{</span>\n  name<span class="token operator">:</span> <span class="token string">&#39;123&#39;</span><span class="token punctuation">,</span>\n  <span class="token function-variable function">getName</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>name\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>person<span class="token punctuation">.</span><span class="token function">getName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// window，（getName 是箭头函数，箭头函数指向外层）</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="_3、作为-构造函数-调用" tabindex="-1"><a class="header-anchor" href="#_3、作为-构造函数-调用" aria-hidden="true">#</a> 3、作为 构造函数 调用</h2><p>通过构造函数生成一个新的对象（object），这是 this 指向这个新对象</p><p>理解这句话 <strong>（最终是被新对象调用的）</strong></p><p>参考 <code>new</code> 关键字的实现</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">3</span>\n\n<span class="token keyword">function</span> <span class="token function">Test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">this</span><span class="token punctuation">.</span>x <span class="token operator">=</span> <span class="token number">4</span>\n  <span class="token keyword">this</span><span class="token punctuation">.</span>y <span class="token operator">=</span> <span class="token number">5</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">var</span> t <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Test</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n \nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>t<span class="token punctuation">.</span>x<span class="token punctuation">,</span> t<span class="token punctuation">.</span>y<span class="token punctuation">)</span> <span class="token comment">// 4,5</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="apply-call-调用" tabindex="-1"><a class="header-anchor" href="#apply-call-调用" aria-hidden="true">#</a> apply / call 调用</h2><p><code>apply</code> 是函数对象的方法，改变函数的调用对象， 第一个参数就是改变后的调用对象，因此 this 也是第一个参数</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">0</span>\n<span class="token keyword">function</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>x<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n<span class="token keyword">var</span> o <span class="token operator">=</span> <span class="token punctuation">{</span>\n  x<span class="token operator">:</span> <span class="token number">1</span>\n<span class="token punctuation">}</span>\n\no<span class="token punctuation">.</span>m <span class="token operator">=</span> test\n\no<span class="token punctuation">.</span><span class="token function">m</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// 0</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><code>apply</code> 参数未空时，默认调用全局对象 <code>winodw</code>，因此运行为 0 ，证明 <code>this</code> 指向全局对象</p><p><code>call</code> 的作用和 apply 作用一样，去吧是写法上</p><ul><li><p>call 传的是多个参数：<code>fun.call(thisArg[,arg1[,arg2,…]]);</code></p></li><li><p>apply 传的是个数组：<code>fun.apply(thisArg, [argsArray]);</code></p></li></ul><h2 id="箭头函数" tabindex="-1"><a class="header-anchor" href="#箭头函数" aria-hidden="true">#</a> 箭头函数</h2><p>所有的箭头函数都没有自己的 <code>this</code>，都会指向外层</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name\n  <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function-variable function">say</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>name\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">var</span> p <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&#39;123&#39;</span><span class="token punctuation">)</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>p<span class="token punctuation">.</span><span class="token function">say</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 123</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>',37),t={href:"https://segmentfault.com/a/1190000017957307",target:"_blank",rel:"noopener noreferrer"},o=(0,p.Uk)("参考1"),c={render:function(n,s){const a=(0,p.up)("OutboundLink");return(0,p.wg)(),(0,p.j4)(p.HY,null,[e,(0,p.Wm)("p",null,[(0,p.Wm)("a",t,[o,(0,p.Wm)(a)])])],64)}}}}]);